// Scoped to .cc-cspd-field-prototype. Generated by microsites/_dversion-build.mjs.
(function () {
  // Use window.document explicitly here — declaring  const document
  // = …  later in this scope hoists the binding to the top of the
  // function as TDZ, so plain  document.querySelector  on this line
  // would throw "Cannot access 'document' before initialization".
  const ROOT = window.document.querySelector('.cc-cspd-field-prototype');
  if (!ROOT) return;

  // Re-bind document.* lookups to resolve against the partial root,
  // so IDs and class selectors can't collide with the host Drupal page.
  const document = new Proxy(window.document, {
    get(target, prop) {
      if (prop === 'getElementById') return (id) => ROOT.querySelector('#' + CSS.escape(id));
      if (prop === 'querySelector') return (sel) => ROOT.querySelector(sel);
      if (prop === 'querySelectorAll') return (sel) => ROOT.querySelectorAll(sel);
      const v = target[prop];
      return typeof v === 'function' ? v.bind(target) : v;
    },
  });

function toggleSection(btn) {
      const section = btn.closest('.section');
      section.classList.toggle('open');
    }

    function stepN(btn, delta) {
      const input = btn.parentElement.querySelector('input');
      const v = parseInt(input.value) || 0;
      const min = parseInt(input.min) || 0;
      const max = parseInt(input.max) || 999;
      input.value = Math.max(min, Math.min(max, v + delta));
      markChanged(btn);
    }

    function markChanged(el) {
      const section = el.closest('.section');
      if (section) section.classList.add('changed');
      triggerSave();
    }

    // Radio selection styling
    document.querySelectorAll('.options input[type="radio"]').forEach(radio => {
      radio.addEventListener('change', function() {
        const name = this.name;
        document.querySelectorAll(`input[name="${name}"]`).forEach(r => {
          r.closest('label').classList.toggle('selected', r.checked);
        });
        markChanged(this);
      });
    });

    // Checkbox styling
    document.querySelectorAll('.options input[type="checkbox"]').forEach(cb => {
      cb.addEventListener('change', function() {
        this.closest('label').classList.toggle('selected', this.checked);
        markChanged(this);
      });
    });

    // Date view tabs
    document.querySelectorAll('.dateview button').forEach(btn => {
      btn.addEventListener('click', function() {
        document.querySelectorAll('.dateview button').forEach(b => b.classList.remove('active'));
        this.classList.add('active');
      });
    });

    // Autosave simulation
    let saveTimer;
    const savedot = document.getElementById('savedot');
    const synctime = document.getElementById('synctime');
    function triggerSave() {
      savedot.textContent = 'saving…';
      savedot.style.color = 'var(--warn)';
      clearTimeout(saveTimer);
      saveTimer = setTimeout(() => {
        savedot.textContent = 'autosaved just now';
        savedot.style.color = 'var(--saved)';
        synctime.textContent = 'just now';
        updateFieldCount();
      }, 700);
    }

    // Listen on all inputs
    document.querySelectorAll('input, textarea').forEach(el => {
      el.addEventListener('input', triggerSave);
    });

    function updateFieldCount() {
      const changedSections = document.querySelectorAll('.section.changed').length;
      document.getElementById('fieldcount').textContent = changedSections;
      // Update status pills
      document.querySelectorAll('.section').forEach(s => {
        const pill = s.querySelector('.status-pill');
        if (s.classList.contains('changed')) {
          pill.classList.remove('default');
          pill.classList.add('changed');
          pill.textContent = 'edited';
        }
      });
    }

  // (No inline on* handlers detected — nothing to expose on window.)
})();
